changeSet.sql:
DO $body$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'carrito'
          AND column_name = 'estado'
          AND udt_name = 'estado_carrito'
    ) THEN
        ALTER TABLE carrito ALTER COLUMN estado TYPE VARCHAR(20) USING estado::VARCHAR;
    END IF;
END $body$;

DO $body$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'pago'
          AND column_name = 'estado'
          AND udt_name = 'estado_pago'
    ) THEN
        ALTER TABLE pago ALTER COLUMN estado TYPE VARCHAR(20) USING estado::VARCHAR;
    END IF;
END $body$;

DO $body$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'pago'
          AND column_name = 'metodo_pago'
          AND udt_name = 'metodo_pago'
    ) THEN
        ALTER TABLE pago ALTER COLUMN metodo_pago TYPE VARCHAR(30) USING metodo_pago::VARCHAR;
    END IF;
END $body$;

DO $body$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'usuario'
          AND column_name = 'rol'
          AND udt_name = 'rol_usuario'
    ) THEN
        ALTER TABLE usuario ALTER COLUMN rol TYPE VARCHAR(10) USING rol::VARCHAR;
    END IF;
END $body$;

DO $body$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'pedido'
          AND column_name = 'estado'
          AND udt_name = 'estado_pedido'
    ) THEN
        -- Desactivar triggers temporalmente para el ALTER
        ALTER TABLE pedido DISABLE TRIGGER ALL;
        ALTER TABLE pedido ALTER COLUMN estado TYPE VARCHAR(20) USING estado::VARCHAR;
        ALTER TABLE pedido ENABLE TRIGGER ALL;
    END IF;
END $body$;
